mapper.select:
SELECT USER_ID, USER_NAME, EMAIL, LAST_LOGIN
FROM T_USER
WHERE USER_ID = #{userId}
  AND PASSWORD = #{password}
  AND USE_YN = 'Y'

mapper.update:
UPDATE T_USER
SET LAST_LOGIN = SYSDATE
WHERE USER_ID = #{userId}

mapper.insert:
INSERT INTO T_USER (
  USER_ID, USER_NAME, PASSWORD, EMAIL, DEPT_CODE, USE_YN, CREATED_AT
) VALUES (
  #{userId}, #{userName}, #{password}, #{email}, #{deptCode}, 'Y', SYSDATE
)

mapper.update:
UPDATE T_USER
SET USER_NAME = #{userName},
    EMAIL = #{email},
    DEPT_CODE = #{deptCode}
WHERE USER_ID = #{userId}

mapper.delete:
UPDATE T_USER
SET USE_YN = 'N', DELETED_AT = SYSDATE
WHERE USER_ID = #{userId}
